import{_ as s,c as n,o as t,ag as e}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/xiangxiang103/status/2044973283423277548","created":"2026-04-17T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/Cloudflare 最新功能 Mesh 保姆级教程：不用公网 IP，把设备和服务器连成私有网络.md","filePath":"ai/bookmark/Cloudflare 最新功能 Mesh 保姆级教程：不用公网 IP，把设备和服务器连成私有网络.md","lastUpdated":1776945928000}'),p={name:"ai/bookmark/Cloudflare 最新功能 Mesh 保姆级教程：不用公网 IP，把设备和服务器连成私有网络.md"};function o(r,a,l,i,c,m){return t(),n("div",null,a[0]||(a[0]=[e(`<p><img src="https://pbs.twimg.com/media/HGEryjdaUAAVW4T?format=jpg&amp;name=large" alt="图像"></p><p>简单来说，Cloudflare Mesh 可以把你的电脑、手机、服务器，甚至是 Cloudflare Workers 连成一个跨地域的局域网。就算没有公网 IP，你的设备之间也能通过私有 IP（默认 100.96.0.0/12）互相访问，比如直连 SSH 或是调用内部 API。对个人开发者和小团队来说，免费额度（50个节点、50个用户）完全管够。</p><p>本文基于 2026-04-14 最新的 Workers VPC 更新整理，主打尝鲜和实操。</p><p><img src="https://pbs.twimg.com/media/HGEttN8awAAppNU?format=jpg&amp;name=large" alt="图像"></p><h2 id="核心概念一览" tabindex="-1">核心概念一览 <a class="header-anchor" href="#核心概念一览" aria-label="Permalink to &quot;核心概念一览&quot;">​</a></h2><p>不搞虚的，这 4 个东西你懂了就知道怎么配：</p><ol><li><strong>Client Device（客户端设备）</strong>：手机和电脑。装上 Cloudflare One 客户端，登录后就能获得一个局域网（Mesh）IP。</li><li><strong>Mesh Node（节点）</strong>：常说的服务端节点，以前叫 WARP Connector。其实就是个没界面的客户端，装在服务器上，让服务器自己加入局域网，或者作为网关把服务器背后的内网设备也拉进来。</li><li><strong>Mesh IP</strong>：组网后分配的私网地址，默认都在 100.96.0.0/12 这个段里。</li><li><strong>Workers VPC</strong>：新功能。这玩意能让运行在边缘节点的 Workers 也能连进你的私有网络，以后写脚本跨网调本地接口更方便了。</li></ol><h2 id="基础玩法-把电脑和服务器连起来" tabindex="-1">基础玩法：把电脑和服务器连起来 <a class="header-anchor" href="#基础玩法-把电脑和服务器连起来" aria-label="Permalink to &quot;基础玩法：把电脑和服务器连起来&quot;">​</a></h2><p>准备工作：一个 CF 账号，一台用来折腾的 Linux 服务器，还有你现在的电脑。</p><p><strong>1. 在云端创建 Node</strong></p><p>登录 CF Dashboard -&gt; <strong>Networking → Mesh</strong>，点 <strong>Add a node</strong>：</p><p><img src="https://pbs.twimg.com/media/HGEt0xAbgAEiFzz?format=jpg&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HGEt5FFaEAAh5nt?format=png&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HGEt8zBbgAAgXWN?format=png&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HGEt_l0bIAA-XZk?format=png&amp;name=large" alt="图像"></p><p>如果是新号，跟着向导一路点就行。老手的话注意确认下设备注册规则、配置文件和 Gateway 代理这些开关有没有打开。</p><p><strong>2. 服务器入网</strong></p><p>建好 Node 后页面会给一段命令和一个 Token：</p><p><img src="https://pbs.twimg.com/media/HGEuGBKawAAL8tU?format=png&amp;name=large" alt="图像"></p><p>**注意：**现在官方的包叫 cloudflare-warp，别自己乱敲 cloudflare-mesh。</p><p>Ubuntu 环境直接复制上面的官方命令安装</p><p>装完后把你的 Token 填进去连上：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo warp-cli connector new &lt;TOKEN&gt;</span></span>
<span class="line"><span>sudo warp-cli connect</span></span></code></pre></div><p>回到 Dashboard 看一眼，变成 Online 就算搞定。</p><p><img src="https://pbs.twimg.com/media/HGEuhvGbQAAzfoF?format=png&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HGEuosXbUAAAUBU?format=jpg&amp;name=large" alt="图像"></p><p><strong>3. 本地电脑入网与测试</strong></p><p>电脑上装好 <strong>WARP 客户端</strong>，下载链接：<a href="https://one.one.one.one/" target="_blank" rel="noreferrer">https://one.one.one.one/</a> ，进去在偏好设置里选 <strong>Zero Trust security</strong>，填好你的 team name 登录。</p><p>显示 Connected 后，你的电脑和服务器就在同一个网络里了。</p><p><img src="https://pbs.twimg.com/media/HGEuxFkbgAAWq_e?format=png&amp;name=large" alt="图像"></p><p><img src="https://pbs.twimg.com/media/HGEuz21awAAhn0B?format=png&amp;name=large" alt="图像"></p><p>找刚才设置的节点的 Mesh IP 试一下</p><p><img src="https://pbs.twimg.com/media/HGEw80DasAA_irf?format=png&amp;name=large" alt="图像"></p><p>只要能通，基础的跨区域局域网就搭完了。</p><p><img src="https://pbs.twimg.com/media/HGEvDi6boAI3bk5?format=png&amp;name=large" alt="图像"></p><h2 id="进阶玩法-让-workers-访问本地服务" tabindex="-1">进阶玩法：让 Workers 访问本地服务 <a class="header-anchor" href="#进阶玩法-让-workers-访问本地服务" aria-label="Permalink to &quot;进阶玩法：让 Workers 访问本地服务&quot;">​</a></h2><p>这是个相当有想象力的功能，你可以把 Worker 绑进局域网里，让它直接去调你服务器上还没暴露到公网的接口（比如内部 AI Agent 或者数据查询 API）。</p><p>在 wrangler.jsonc （或 toml）里绑定网络：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;$schema&quot;: &quot;./node_modules/wrangler/config-schema.json&quot;,</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;mesh-gateway&quot;,</span></span>
<span class="line"><span>  &quot;main&quot;: &quot;src/index.js&quot;,</span></span>
<span class="line"><span>  &quot;compatibility_date&quot;: &quot;2026-04-16&quot;,</span></span>
<span class="line"><span>  &quot;vpc_networks&quot;: [</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>      &quot;binding&quot;: &quot;MESH&quot;,</span></span>
<span class="line"><span>      &quot;network_id&quot;: &quot;cf1:network&quot;,</span><span> // 固定写法，别乱改</span></span>
<span class="line"><span>      &quot;remote&quot;: true</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>代码里直接通过局域网地址请求：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const NODE_IP = &quot;100.96.1.50&quot;;</span></span>
<span class="line"><span>const NODE_PORT = 8080;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>export default {</span></span>
<span class="line"><span>  async fetch(request, env) {</span></span>
<span class="line"><span>    try {</span></span>
<span class="line"><span>      // 魔法就在这行，直接 fetch 你的内网接口</span></span>
<span class="line"><span>      return await env.MESH.fetch(\\\`http://\${NODE_IP}:\${NODE_PORT}/api/data\\\`);</span></span>
<span class="line"><span>    } catch (error) {</span></span>
<span class="line"><span>      return new Response(&quot;Service unavailable&quot;, { status: 503 });</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>};</span></span></code></pre></div><p>如果你想连的是组网服务器局域网里的其它机器（例如 10.0.1.50），只要 Mesh Node 那边做好了路由，同样可以直接用局域网 IP 去 fetch。</p><h2 id="防踩坑指南" tabindex="-1">防踩坑指南 <a class="header-anchor" href="#防踩坑指南" aria-label="Permalink to &quot;防踩坑指南&quot;">​</a></h2><p>跑不通的时候别急着怀疑人生，重点看看这几个坑：</p><ul><li><strong>最大的坑：分割隧道（Split Tunnel）把你拉黑了</strong> 客户端默认的排除策略里很可能会包含 100.64.0.0/10，而 Mesh 分配的段刚好是 100.96.0.0/12（后者被前者的网段包含进去了）。这会导致你本地发往 Mesh IP 的请求根本不走 CF 代理。赶紧去 Zero Trust 后台的 Settings 检查下，把不该屏蔽的段给放行。</li></ul><p><img src="https://pbs.twimg.com/media/HGEvSMta4AEi9C-?format=jpg&amp;name=large" alt="图像"></p><ul><li><strong>认清现实：只能用 IP，别整域名</strong> 目前 Workers 调局域网服务只支持 IP 访问。虽然看着不够优雅，但也只能先这么用着，官方承诺的 Mesh DNS 支持后期会跟上。</li><li><strong>老老实实敲命令，别等 Docker</strong> 目前主要靠客户端或 Connector 接入，如果你想找 Docker 部署方案，还得再等等，官方的镜像还在画大饼阶段。</li><li><strong>排障小建议</strong> 如果 Dashboard 显示节点在线但死活连不通：</li></ul><ol><li>Windows 试试 Find-NetRoute -RemoteIPAddress &quot;100.96.0.1&quot; | Select-Object -Last 1 看看流量到底走没走 WARP。</li><li>看下服务器有没有放行 100.96.0.0/12 的安全组和防火墙规则。</li><li>Ping 不通未必是网断了，可能单纯是你的服务器在装“死”禁了 ICMP，用 SSH 或者 curl 再确认一下。</li></ol><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>如果是日常用，前三个大步骤走完就足够你白嫖一个稳定的远程访问环境。如果你是生产需求想用 Workers VPC，考虑到它还在灰度期，上线前自己多测测，多盯紧一下官方文档。</p><p><strong>文章同步公众号：雨哥聊AI</strong></p>`,51)]))}const u=s(p,[["render",o]]);export{d as __pageData,u as default};
